def classify_intent(user_msg):
    response = anthropic_client.messages.create(
        model="claude-opus-4-7-1m",
        messages=[{
          "role": "user",
          "content": f"""You are an intent classifier...
          (50 lines of prompt inlined here)
          User: {user_msg}"""
        }],
    )
    return response.content[0].text
